import includes from './includes';
import {
  AVAILABLE_CURRENCIES,
  DEFAULT_DECIMALS_AMOUNT,
  DECIMALS_BY_CURRENCY_ID,
} from '../constants/currencies';

/**
 * @param {number} [maxDecimals]
 * @param {import('../..').CurrencyId} [currencyId]
 */
const computeMaxDecimals = (maxDecimals, currencyId) => {
  if (typeof maxDecimals !== 'undefined' && maxDecimals >= 0) return maxDecimals;
  if (currencyId && includes(Object.values(AVAILABLE_CURRENCIES), currencyId)) {
    return DECIMALS_BY_CURRENCY_ID[currencyId];
  }
  return DEFAULT_DECIMALS_AMOUNT;
};

export default computeMaxDecimals;
